const {
  Document,
  Packer,
  Paragraph,
  TextRun,
  Table,
  TableRow,
  TableCell,
  HeadingLevel,
  AlignmentType,
  BorderStyle,
  WidthType,
  ShadingType,
  VerticalAlign,
} = require("docx");
const fs = require("fs");

const summary = JSON.parse(fs.readFileSync("manager/tools/employee_summary.json", "utf8"));

const candidates = summary.candidates;
const topDept = summary.top_perf_dept;
const promotionCount = summary.promotion_count;

// Avg salary formatted
const avgSalaryLines = Object.entries(summary.avg_salary_per_dept)
  .map(([dept, sal]) => `${dept}: $${sal.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`)
  .join(", ");

const avgPerfLines = Object.entries(summary.avg_perf_per_dept)
  .map(([dept, score]) => `${dept}: ${score.toFixed(1)}`)
  .join(", ");

// Table border helper
const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };

// Header cell factory
function headerCell(text, widthDXA) {
  return new TableCell({
    borders,
    width: { size: widthDXA, type: WidthType.DXA },
    shading: { fill: "2E75B6", type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    verticalAlign: VerticalAlign.CENTER,
    children: [
      new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text, bold: true, color: "FFFFFF", font: "Arial", size: 20 })],
      }),
    ],
  });
}

// Data cell factory
function dataCell(text, widthDXA, align = AlignmentType.LEFT, bold = false) {
  return new TableCell({
    borders,
    width: { size: widthDXA, type: WidthType.DXA },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    verticalAlign: VerticalAlign.CENTER,
    children: [
      new Paragraph({
        alignment: align,
        children: [new TextRun({ text, bold, font: "Arial", size: 20 })],
      }),
    ],
  });
}

// Column widths (total content width for US Letter 1" margins = 9360 DXA)
const colWidths = [2200, 2100, 2060, 3000];
const tableWidth = colWidths.reduce((a, b) => a + b, 0); // 9360

// Header row
const headerRow = new TableRow({
  tableHeader: true,
  children: [
    headerCell("Name", colWidths[0]),
    headerCell("Department", colWidths[1]),
    headerCell("Salary", colWidths[2]),
    headerCell("Performance Score", colWidths[3]),
  ],
});

// Data rows
const dataRows = candidates.map((c, idx) => {
  const fillColor = idx % 2 === 0 ? "F5F9FD" : "FFFFFF";
  return new TableRow({
    children: [
      new TableCell({
        borders,
        width: { size: colWidths[0], type: WidthType.DXA },
        shading: { fill: fillColor, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        children: [new Paragraph({ children: [new TextRun({ text: c.Name, font: "Arial", size: 20 })] })],
      }),
      new TableCell({
        borders,
        width: { size: colWidths[1], type: WidthType.DXA },
        shading: { fill: fillColor, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        children: [new Paragraph({ children: [new TextRun({ text: c.Department, font: "Arial", size: 20 })] })],
      }),
      new TableCell({
        borders,
        width: { size: colWidths[2], type: WidthType.DXA },
        shading: { fill: fillColor, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        children: [
          new Paragraph({
            alignment: AlignmentType.RIGHT,
            children: [new TextRun({ text: `$${c.Salary.toLocaleString("en-US")}`, font: "Arial", size: 20 })],
          }),
        ],
      }),
      new TableCell({
        borders,
        width: { size: colWidths[3], type: WidthType.DXA },
        shading: { fill: fillColor, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        children: [
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: `${c.PerformanceScore} / 5`, bold: true, font: "Arial", size: 20 })],
          }),
        ],
      }),
    ],
  });
});

const today = new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" });

const executiveSummary =
  `As of ${today}, a comprehensive review of employee tenure and performance data has identified ${promotionCount} employees as promotion candidates. ` +
  `These individuals have been with the organization for more than five years and have demonstrated consistently high performance, each scoring 4 or above (out of 5) on the company's performance evaluation scale. ` +
  `The ${topDept} department leads all departments with the highest average performance score (${summary.avg_perf_per_dept[topDept].toFixed(1)}), underscoring its sustained excellence. ` +
  `Average salaries by department are as follows: ${avgSalaryLines}. ` +
  `It is recommended that Human Resources initiate formal promotion review discussions with each identified candidate during the next performance cycle to recognize their contributions and support long-term retention.`;

const doc = new Document({
  styles: {
    default: {
      document: { run: { font: "Arial", size: 22 } },
    },
    paragraphStyles: [
      {
        id: "Heading1",
        name: "Heading 1",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 36, bold: true, font: "Arial", color: "2E75B6" },
        paragraph: { spacing: { before: 300, after: 200 }, outlineLevel: 0 },
      },
      {
        id: "Heading2",
        name: "Heading 2",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 26, bold: true, font: "Arial", color: "1F4E79" },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 1 },
      },
    ],
  },
  sections: [
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 },
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
      children: [
        // Report date
        new Paragraph({
          alignment: AlignmentType.RIGHT,
          children: [new TextRun({ text: today, font: "Arial", size: 18, color: "666666" })],
          spacing: { after: 100 },
        }),

        // Main heading
        new Paragraph({
          heading: HeadingLevel.HEADING_1,
          children: [new TextRun({ text: "Promotion Candidates Report", font: "Arial", size: 36, bold: true, color: "2E75B6" })],
        }),

        // Divider line via border
        new Paragraph({
          border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: "2E75B6", space: 1 } },
          spacing: { after: 240 },
          children: [],
        }),

        // Executive Summary heading
        new Paragraph({
          heading: HeadingLevel.HEADING_2,
          children: [new TextRun({ text: "Executive Summary", font: "Arial", size: 26, bold: true, color: "1F4E79" })],
        }),

        // Executive summary paragraph
        new Paragraph({
          spacing: { after: 320, line: 360 },
          children: [new TextRun({ text: executiveSummary, font: "Arial", size: 22 })],
        }),

        // Key metrics heading
        new Paragraph({
          heading: HeadingLevel.HEADING_2,
          children: [new TextRun({ text: "Key Metrics", font: "Arial", size: 26, bold: true, color: "1F4E79" })],
        }),

        // Metrics table (2-col simple)
        new Table({
          width: { size: tableWidth, type: WidthType.DXA },
          columnWidths: [4680, 4680],
          rows: [
            new TableRow({
              children: [
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  shading: { fill: "EBF3FB", type: ShadingType.CLEAR },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: "Top Performance Department", bold: true, font: "Arial", size: 20 })] })],
                }),
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: `${topDept} (avg score: ${summary.avg_perf_per_dept[topDept].toFixed(1)})`, font: "Arial", size: 20 })] })],
                }),
              ],
            }),
            new TableRow({
              children: [
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  shading: { fill: "EBF3FB", type: ShadingType.CLEAR },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: "Total Promotion Candidates", bold: true, font: "Arial", size: 20 })] })],
                }),
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: `${promotionCount}`, font: "Arial", size: 20 })] })],
                }),
              ],
            }),
            new TableRow({
              children: [
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  shading: { fill: "EBF3FB", type: ShadingType.CLEAR },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: "Criteria", bold: true, font: "Arial", size: 20 })] })],
                }),
                new TableCell({
                  borders,
                  width: { size: 4680, type: WidthType.DXA },
                  margins: { top: 80, bottom: 80, left: 120, right: 120 },
                  children: [new Paragraph({ children: [new TextRun({ text: "Tenure > 5 years AND Performance Score >= 4", font: "Arial", size: 20 })] })],
                }),
              ],
            }),
          ],
        }),

        new Paragraph({ spacing: { after: 240 }, children: [] }),

        // Candidates table heading
        new Paragraph({
          heading: HeadingLevel.HEADING_2,
          children: [new TextRun({ text: "Promotion Candidates", font: "Arial", size: 26, bold: true, color: "1F4E79" })],
        }),

        // Candidates table
        new Table({
          width: { size: tableWidth, type: WidthType.DXA },
          columnWidths: colWidths,
          rows: [headerRow, ...dataRows],
        }),

        new Paragraph({ spacing: { after: 240 }, children: [] }),

        // Footer note
        new Paragraph({
          border: { top: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC", space: 1 } },
          spacing: { before: 200 },
          children: [
            new TextRun({
              text: "Confidential — For internal HR use only. Generated automatically from employee performance data.",
              font: "Arial",
              size: 16,
              color: "888888",
              italics: true,
            }),
          ],
        }),
      ],
    },
  ],
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("outputs/promotion_report.docx", buffer);
  console.log("Saved outputs/promotion_report.docx");
});

